public class SignInForm {
    private JFrame frame;
    private JTextField usernameField;
    private JPasswordField passwordField;
    private JButton submitButton;
    private JButton toggleVisButton;
    private JLabel errorLabel;
    private JCheckBox rememberCheckBox;

    public SignInForm() {
        createGUI();
    }

    private void createGUI() {
        frame = new JFrame("Sign in");
        frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        frame.setLayout(new BorderLayout());

        JPanel cardPanel = new JPanel();
        cardPanel.setLayout(new BoxLayout(cardPanel, BoxLayout.Y_AXIS));

        JLabel promptLabel = new JLabel("$ auth --request session");
        promptLabel.setFont(new Font("Monospaced", Font.PLAIN, 12));
        cardPanel.add(promptLabel);

        JLabel titleLabel = new JLabel("Sign in");
        titleLabel.setFont(new Font("Monospaced", Font.BOLD, 18));
        cardPanel.add(titleLabel);

        JPanel formPanel = new JPanel();
        formPanel.setLayout(new BoxLayout(formPanel, BoxLayout.Y_AXIS));

        JPanel fieldPanel = new JPanel();
        fieldPanel.setLayout(new FlowLayout(FlowLayout.LEFT));
        JLabel usernameLabel = new JLabel("Username or email:");
        fieldPanel.add(usernameLabel);
        usernameField = new JTextField(20);
        fieldPanel.add(usernameField);
        cardPanel.add(fieldPanel);

        fieldPanel = new JPanel();
        fieldPanel.setLayout(new FlowLayout(FlowLayout.LEFT));
        JLabel passwordLabel = new JLabel("Password:");
        fieldPanel.add(passwordLabel);
        passwordField = new JPasswordField(20);
        fieldPanel.add(passwordField);
        toggleVisButton = new JButton("show");
        toggleVisButton.addActionListener(new ToggleVisButtonListener());
        fieldPanel.add(toggleVisButton);
        cardPanel.add(fieldPanel);

        errorLabel = new JLabel("Enter a username and password.");
        errorLabel.setFont(new Font("Monospaced", Font.PLAIN, 12));
        errorLabel.setForeground(Color.RED);
        cardPanel.add(errorLabel);

        JPanel rowPanel = new JPanel();
        rowPanel.setLayout(new FlowLayout(FlowLayout.LEFT));
        rememberCheckBox = new JCheckBox("remember me");
        rowPanel.add(rememberCheckBox);
        JLabel forgotPasswordLabel = new JLabel("forgot password");
        forgotPasswordLabel.setForeground(Color.BLUE);
        forgotPasswordLabel.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        forgotPasswordLabel.addMouseListener(new ForgotPasswordMouseListener());
        rowPanel.add(forgotPasswordLabel);
        cardPanel.add(rowPanel);

        submitButton = new JButton("Connect");
        submitButton.addActionListener(new SubmitButtonListener());
        cardPanel.add(submitButton);

        frame.add(cardPanel, BorderLayout.CENTER);

        JPanel footerPanel = new JPanel();
        footerPanel.setLayout(new FlowLayout(FlowLayout.CENTER));
        JLabel footerNoteLabel = new JLabel("no account? <a href='#'>request access</a>");
        footerNoteLabel.setForeground(Color.GRAY);
        footerNoteLabel.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        footerNoteLabel.addMouseListener(new FooterNoteMouseListener());
        footerPanel.add(footerNoteLabel);
        frame.add(footerPanel, BorderLayout.PAGE_END);

        frame.pack();
        frame.setVisible(true);
    }

    private class ToggleVisButtonListener implements ActionListener {
        public void actionPerformed(ActionEvent e) {
            String passwordType = passwordField.getPassword().getClass().getSimpleName();
            if (passwordType.equals("char[]")) {
                passwordField.setEchoChar('\0');
                toggleVisButton.setText("hide");
            } else {
                passwordField.setEchoChar('*');
                toggleVisButton.setText("show");
            }
        }
    }

    private class SubmitButtonListener implements ActionListener {
        public void actionPerformed(ActionEvent e) {
            String username = usernameField.getText().trim();
            String password = new String(passwordField.getPassword());

            if (username.isEmpty() || password.isEmpty()) {
                errorLabel.setText("Enter a username and password.");
                errorLabel.setVisible(true);
                return;
            }
            errorLabel.setVisible(false);
            submitButton.setText("Connecting...");
            submitButton.setEnabled(false);

            // Replace this block with a real request to your auth endpoint.
            new Thread(() -> {
                try {
                    Thread.sleep(700);
                } catch (InterruptedException ex) {
                    Thread.currentThread().interrupt();
                }
                SwingUtilities.invokeLater(() -> {
                    submitButton.setText("Connect");
                    submitButton.setEnabled(true);
                    JOptionPane.showMessageDialog(frame, "Wire this up to your backend auth endpoint.");
                });
            }).start();
        }
    }

    private class ForgotPasswordMouseListener implements MouseListener {
        public void mouseClicked(MouseEvent e) {
            // Replace this block with a real request to your auth endpoint.
            JOptionPane.showMessageDialog(frame, "Wire this up to your backend auth endpoint.");
        }

        public void mousePressed(MouseEvent e) {}

        public void mouseReleased(MouseEvent e) {}

        public void mouseEntered(MouseEvent e) {}

        public void mouseExited(MouseEvent e) {}
    }

    private class FooterNoteMouseListener implements MouseListener {
        public void mouseClicked(MouseEvent e) {
            // Replace this block with a real request to your auth endpoint.
            JOptionPane.showMessageDialog(frame, "Wire this up to your backend auth endpoint.");
        }

        public void mousePressed(MouseEvent e) {}

        public void mouseReleased(MouseEvent e) {}

        public void mouseEntered(MouseEvent e) {}

        public void mouseExited(MouseEvent e) {}
    }

    public static void main(String[] args) {
        new SignInForm();
    }
}

